// Process and structure analytics data
const contentId = $node["Get Recent Posts"].json.id;
const postId = $node["Get Recent Posts"].json.post_id;
const analytics = $json;

// Extract metrics
const metrics = [
  {
    metric_type: 'impressions',
    metric_value: analytics.impressionCount || 0
  },
  {
    metric_type: 'clicks',
    metric_value: analytics.clickCount || 0
  },
  {
    metric_type: 'likes',
    metric_value: analytics.likeCount || 0
  },
  {
    metric_type: 'comments',
    metric_value: analytics.commentCount || 0
  },
  {
    metric_type: 'shares',
    metric_value: analytics.shareCount || 0
  }
];

// Calculate engagement rate
const totalEngagement = analytics.likeCount + analytics.commentCount + analytics.shareCount;
const engagementRate = analytics.impressionCount > 0 ? 
  (totalEngagement / analytics.impressionCount * 100).toFixed(2) : 0;

return metrics.map(metric => ({
  content_id: contentId,
  post_id: postId,
  platform: 'linkedin',
  ...metric,
  engagement_rate: engagementRate,
  recorded_at: new Date().toISOString()
}));

// Get hashtags from recent posts and update performance
const posts = $items("Get Recent Posts");
const hashtagData = [];

for (const post of posts) {
  if (post.json.hashtags) {
    const hashtags = JSON.parse(post.json.hashtags);
    const analytics = $items("Process Analytics Data").find(
      item => item.json.post_id === post.json.post_id
    );

    if (analytics) {
      const reach = analytics.json.metric_value || 0;
      const engagement = analytics.json.engagement_rate || 0;

      for (const hashtag of hashtags) {
        hashtagData.push({
          platform: 'linkedin',
          hashtag: hashtag,
          reach: reach,
          engagement: engagement
        });
      }
    }
  }
}

return hashtagData;

// Call stored procedure to update hashtag performance
const hashtagData = $json;

if (hashtagData.length > 0) {
  const hashtags = JSON.stringify(hashtagData.map(h => h.hashtag));
  const totalReach = hashtagData.reduce((sum, h) => sum + h.reach, 0);
  const avgEngagement = hashtagData.reduce((sum, h) => sum + h.engagement, 0) / hashtagData.length;

  return {
    platform: 'linkedin',
    hashtags: hashtags,
    reach: totalReach,
    engagement: Math.round(avgEngagement)
  };
}

return { skip: true };

// Generate analytics report
const profileAnalytics = $items("Fetch Profile Analytics")[0]?.json || {};
const postsAnalyzed = $items("Get Recent Posts").length;
const totalImpressions = $items("Process Analytics Data")
  .filter(item => item.json.metric_type === 'impressions')
  .reduce((sum, item) => sum + item.json.metric_value, 0);

const totalEngagement = $items("Process Analytics Data")
  .filter(item => ['likes', 'comments', 'shares'].includes(item.json.metric_type))
  .reduce((sum, item) => sum + item.json.metric_value, 0);

const report = {
  workflow: 'LinkedIn Analytics Tracker',
  execution_time: new Date().toISOString(),
  summary: {
    posts_analyzed: postsAnalyzed,
    total_impressions: totalImpressions,
    total_engagement: totalEngagement,
    avg_engagement_rate: totalImpressions > 0 ? 
      (totalEngagement / totalImpressions * 100).toFixed(2) : 0,
    profile_views: profileAnalytics.profileViews || 0,
    unique_visitors: profileAnalytics.uniqueVisitors || 0
  },
  status: 'success'
};

return report;

// Error handling
const error = $json.error || 'Unknown error occurred';
const context = {
  workflow: 'LinkedIn Analytics Tracker',
  error: error,
  timestamp: new Date().toISOString(),
  node: $executionId
};

// Log error to database
await $workflow.postgres.executeQuery({
  query: `INSERT INTO automation_logs (workflow_name, status, message, error_details) VALUES ('LinkedIn Analytics Tracker', 'failed', '${error}', '${JSON.stringify(context)}')`
});

return context;
